// BenchmarkRunner.cs
public sealed class BenchmarkRunner : IBenchmarkRunner, IAsyncDisposable
{
    private readonly SemaphoreSlim _serverLock = new(1, 1);
    private readonly ConcurrentDictionary<Guid, BenchmarkState> _states = new();
    private readonly ILogger<BenchmarkRunner> _logger;
    private readonly DockerHarness _harness;
    private readonly string _logsRoot;

    public BenchmarkRunner(DockerHarness harness, ILogger<BenchmarkRunner> logger, string logsRoot)
    {
        _harness = harness;
        _logger = logger;
        _logsRoot = logsRoot;
    }

    public async Task<Guid> StartBenchmarkAsync(BenchmarkContext context, CancellationToken ct = default)
    {
        var id = Guid.NewGuid();
        var state = new BenchmarkState(context, id);
        _states[id] = state;

        try
        {
            await _serverLock.WaitAsync(ct);
            try
            {
                await _harness.StartModelServerAsync(context.Model, ct);
                state.Status = BenchmarkStatus.Running;
                _logger.LogInformation("Started benchmark {Id} for {Model}", id, context.Model);
            }
            finally
            {
                _serverLock.Release();
            }

            // Run experiments concurrently per constraint
            var tasks = context.Constraints.Select(async constraint =>
            {
                var result = await RunExperimentAsync(context, constraint, ct);
                state.AddResult(constraint, result);
            });

            await Task.WhenAll(tasks);
            state.Status = BenchmarkStatus.Completed;
        }
        catch (Exception ex)
        {
            state.Status = BenchmarkStatus.Failed;
            state.Error = ex;
            _logger.LogError(ex, "Benchmark {Id} failed", id);
        }
        finally
        {
            await _harness.StopModelServerAsync(ct);
        }

        return id;
    }

